"f":"Yura","l":"Konakov","c":[{"t":"driver_licence"},{"t":"electrical_licence","e":"2028-11-13"},{"t":"white_card"},{"t":"open_cabling","e":"2027-08-15"},{"t":"working_at_heights"},{"t":"confined_space"},{"t":"scissor_lift"},{"t":"boom_lift"},{"t":"vertical_lift"},{"t":"hrwl_boom_11m"},{"t":"forklift_hrwl"},{"t":"hrwl_dogging"},{"t":"riw"},{"t":"first_aid"},{"t":"cpr"},{"t":"lvr"},{"t":"other"},{"t":"hv_switching"},{"t":"hv_operators"},{"t":"manual_handling"},{"t":"silica_awareness"}]}]'::jsonb;
  v_w      jsonb;
  v_c      jsonb;
  v_exp    date;
  v_status worker_credential_status;
BEGIN
  SELECT id INTO v_admin FROM auth.users WHERE email = 'royce@eq.solutions' LIMIT 1;

  FOR v_w IN SELECT value FROM jsonb_array_elements(v_data) LOOP
    INSERT INTO public.workers (first_name, last_name)
    VALUES (v_w->>'f', v_w->>'l')
    RETURNING id INTO v_id;

    FOR v_c IN SELECT value FROM jsonb_array_elements(v_w->'c') LOOP
      v_exp    := (v_c->>'e')::date;
      v_status := CASE WHEN v_exp IS NOT NULL AND v_exp < CURRENT_DATE
                    THEN 'expired'::worker_credential_status
                    ELSE 'active'::worker_credential_status END;
      INSERT INTO public.worker_credentials (worker_id, credential_type, expiry_date, status)
      VALUES (v_id, (v_c->>'t')::worker_credential_type, v_exp, v_status);
    END LOOP;

    INSERT INTO public.worker_invites (org_id, worker_id, created_by)
    VALUES ('00000000-0000-0000-0000-000000000002', v_id, v_admin);
  END LOOP;
END $$;